// src/adapters/polymarket-deposit-wallet.test.ts
// LOCKS the hand-ported UUPS deposit-wallet derivation to the OFFICIAL SDK's exact
// output. The expected addresses were generated by running
// @polymarket/builder-relayer-client's deriveDepositWallet(eoa, factory, impl) in
// the PolyNews tree (where the SDK is installed) — so if our viem port drifts a
// single byte from the SDK, these fail. This is the byte-exact lock that lets the
// MCP keep the SDK out of its prod dep tree without hand-rolling crypto blind.
import { test } from "node:test";
import assert from "node:assert/strict";
import {
  deriveDepositWalletUUPS,
  deriveDepositWalletBeacon,
  resolveDepositWallet,
  _clearDwCache,
  initCodeHashERC1967,
  initCodeHashERC1967Beacon,
  isBeaconResult,
  assertUUPSFactory,
  signPoly1271Order,
  type Poly1271Order,
  type DwResolveRpc,
  DEPOSIT_WALLET_FACTORY,
  DEPOSIT_WALLET_IMPLEMENTATION,
  DEPOSIT_WALLET_BEACON,
} from "./polymarket-deposit-wallet.js";
import { getAddress, hexToBytes, type Hex } from "viem";
import { makeEvmSigner } from "../signers/evm.js";

// (EOA owner) -> (deposit wallet) — verbatim from the SDK deriveDepositWallet().
const SDK_VECTORS: ReadonlyArray<readonly [Hex, Hex]> = [
  ["0xA6350f11AF9Bd54603EDaB09871737539c35D0e0", "0x648dDfB3b6338Ba33cCD413042764D1B72Fb7951"],
  ["0x0000000000000000000000000000000000000001", "0x57ffBc34De23124fAeb8387fcd689d314E57aCcD"],
  ["0x92C0d39f947d371bC9a8323ce3f110ab4663eFFD", "0x24f1036FE0ae555b3EF81fe0b43d024033BD4f07"],
];

for (const [eoa, expected] of SDK_VECTORS) {
  test(`deriveDepositWalletUUPS matches the SDK vector for ${eoa}`, () => {
    assert.equal(deriveDepositWalletUUPS(eoa), expected); // checksummed exact match
  });
}

test("derivation uses the SDK-config factory + UUPS implementation", () => {
  assert.equal(DEPOSIT_WALLET_FACTORY, "0x00000000000Fb5C9ADea0298D729A0CB3823Cc07");
  assert.equal(DEPOSIT_WALLET_IMPLEMENTATION, "0x58CA52ebe0DadfdF531Cde7062e76746de4Db1eB");
});

test("initCodeHashERC1967 is deterministic + 32 bytes", () => {
  const args = "0x" + "00".repeat(64);
  const h1 = initCodeHashERC1967(DEPOSIT_WALLET_IMPLEMENTATION, args as Hex);
  const h2 = initCodeHashERC1967(DEPOSIT_WALLET_IMPLEMENTATION, args as Hex);
  assert.equal(h1, h2);
  assert.equal(h1.length, 66); // 0x + 32 bytes
});

test("isBeaconResult: zero/empty => UUPS, non-zero word => beacon", () => {
  assert.equal(isBeaconResult("0x"), false);
  assert.equal(isBeaconResult("0x" + "0".repeat(64)), false);
  assert.equal(isBeaconResult("0x" + "0".repeat(24) + "1".repeat(40)), true);
});

// ── Beacon derivation — locked to SDK 0.0.10 deriveBeaconDepositWallet ─────────
// Same EOAs as SDK_VECTORS, expected addresses generated by the SDK with the LIVE
// beacon (factory.beacon() on Polygon, 2026-07-01). The last pair is the deployed
// production loading DW — verified to have code on-chain, the strongest vector.
const SDK_BEACON_VECTORS: ReadonlyArray<readonly [Hex, Hex]> = [
  ["0xA6350f11AF9Bd54603EDaB09871737539c35D0e0", "0x6A5B3801a27F948572A0eF29465c879F1457BA26"],
  ["0x0000000000000000000000000000000000000001", "0x94bF330955A0b957662fEaF878dE77bf25f76cD9"],
  ["0x92C0d39f947d371bC9a8323ce3f110ab4663eFFD", "0xec0012d2F4c6D4a257Dd4a22d0B5Ddc75ddb6986"],
  ["0x5931210e759c8C684dD8e10F40a0903399647842", "0xde3539C0d39b1A5DBA7Cc12eDc9cAe5368DF46A4"],
];

for (const [eoa, expected] of SDK_BEACON_VECTORS) {
  test(`deriveDepositWalletBeacon matches the SDK vector for ${eoa}`, () => {
    assert.equal(getAddress(deriveDepositWalletBeacon(eoa)), getAddress(expected));
  });
}

test("beacon constant matches the live factory.beacon() read", () => {
  assert.equal(DEPOSIT_WALLET_BEACON, "0x7A18EDfe055488A3128f01F563e5B479D92ffc3a");
});

test("initCodeHashERC1967Beacon is deterministic + 32 bytes + differs from UUPS", () => {
  const args = ("0x" + "00".repeat(64)) as Hex;
  const h1 = initCodeHashERC1967Beacon(DEPOSIT_WALLET_BEACON, args);
  assert.equal(h1, initCodeHashERC1967Beacon(DEPOSIT_WALLET_BEACON, args));
  assert.equal(h1.length, 66);
  assert.notEqual(h1, initCodeHashERC1967(DEPOSIT_WALLET_IMPLEMENTATION, args));
});

// ── resolveDepositWallet: era detection via on-chain code ───────────────────────
const OWNER = "0x5931210e759c8C684dD8e10F40a0903399647842" as Hex;
const OWNER_UUPS = deriveDepositWalletUUPS(OWNER);
const OWNER_BEACON = deriveDepositWalletBeacon(OWNER);

function fakeRpc(opts: { codeAt?: string[]; beaconCall?: string | Error }): DwResolveRpc {
  const withCode = new Set((opts.codeAt ?? []).map((a) => a.toLowerCase()));
  return {
    async getCode(address: string) {
      return withCode.has(address.toLowerCase()) ? "0x60806040" : "0x";
    },
    async callReadonly() {
      if (opts.beaconCall instanceof Error) throw opts.beaconCall;
      return opts.beaconCall ?? "0x";
    },
  };
}

test("resolveDepositWallet: prefers a DEPLOYED legacy UUPS wallet", async () => {
  _clearDwCache();
  const dw = await resolveDepositWallet(OWNER, fakeRpc({ codeAt: [OWNER_UUPS] }));
  assert.equal(dw, OWNER_UUPS);
});

test("resolveDepositWallet: falls to the DEPLOYED beacon wallet when UUPS is empty", async () => {
  _clearDwCache();
  const dw = await resolveDepositWallet(OWNER, fakeRpc({ codeAt: [OWNER_BEACON] }));
  assert.equal(dw, OWNER_BEACON);
});

test("resolveDepositWallet: fresh owner + beacon-mode factory => beacon derivation", async () => {
  _clearDwCache();
  const beaconWord = "0x" + "0".repeat(24) + DEPOSIT_WALLET_BEACON.slice(2).toLowerCase();
  const dw = await resolveDepositWallet(OWNER, fakeRpc({ beaconCall: beaconWord }));
  assert.equal(getAddress(dw), getAddress(OWNER_BEACON));
});

test("resolveDepositWallet: fresh owner + UUPS-mode factory (revert/zero) => UUPS derivation", async () => {
  _clearDwCache();
  assert.equal(await resolveDepositWallet(OWNER, fakeRpc({ beaconCall: new Error("execution reverted") })), OWNER_UUPS);
  _clearDwCache();
  assert.equal(await resolveDepositWallet(OWNER, fakeRpc({ beaconCall: "0x" + "0".repeat(64) })), OWNER_UUPS);
});

test("resolveDepositWallet: caches DEPLOYED resolutions, not fresh ones", async () => {
  _clearDwCache();
  // Deployed → cached: a second resolve with a blind rpc still answers.
  await resolveDepositWallet(OWNER, fakeRpc({ codeAt: [OWNER_BEACON] }));
  const blind: DwResolveRpc = {
    async getCode() { throw new Error("must not be called — cached"); },
    async callReadonly() { throw new Error("must not be called — cached"); },
  };
  assert.equal(await resolveDepositWallet(OWNER, blind), OWNER_BEACON);
  // Fresh → NOT cached: the next resolve re-probes (and now finds a deployed wallet).
  _clearDwCache();
  await resolveDepositWallet(OWNER, fakeRpc({ beaconCall: new Error("revert") })); // fresh => uups, uncached
  const dw = await resolveDepositWallet(OWNER, fakeRpc({ codeAt: [OWNER_BEACON] }));
  assert.equal(dw, OWNER_BEACON);
});

test("assertUUPSFactory: passes on revert/zero, THROWS on a real beacon", async () => {
  await assertUUPSFactory(async () => {
    throw new Error("execution reverted");
  }); // revert => UUPS => no throw
  await assertUUPSFactory(async () => "0x" + "0".repeat(64)); // zero => UUPS => no throw
  await assert.rejects(
    () => assertUUPSFactory(async () => "0x" + "0".repeat(24) + "ab".repeat(20)),
    /BeaconProxy now, not/,
  );
});

// ── POLY_1271 (ERC-7739) signing — locked to the SDK vector ─────────────────
// Fixed test key 0x11..11; the EOA + deposit wallet + signature were generated by
// the REAL clob-client-v2 inner-sig primitive (viem walletClient.signTypedData) over
// the documented buildOrderSignature construction. If our hashTypedData + @noble
// signer drift one byte from the SDK, this fails.
const TEST_KEY = hexToBytes(("0x" + "11".repeat(32)) as Hex);
const TEST_EOA = "0x19E7E376E7C213B7E7e7e46cc70A5dD086DAff2A";
const TEST_DW = "0x7a57144fAfde87F5cE4a880D570BAe58eeBC83f2";
const VECTOR_SIG =
  "";

test("fixed key derives the SDK's EOA + deposit wallet (ties signing to derivation)", () => {
  const signer = makeEvmSigner(TEST_KEY);
  assert.equal(getAddress(signer.address), getAddress(TEST_EOA));
  assert.equal(deriveDepositWalletUUPS(getAddress(TEST_EOA)), getAddress(TEST_DW));
});

test("signPoly1271Order matches the SDK ERC-7739 vector byte-for-byte", () => {
  const signer = makeEvmSigner(TEST_KEY);
  const order: Poly1271Order = {
    salt: "479249096012",
    maker: getAddress(TEST_DW),
    signer: getAddress(TEST_DW),
    tokenId: "123456789",
    makerAmount: "1000000",
    takerAmount: "2000000",
    side: 0,
    signatureType: 3,
    timestamp: "1700000000000",
    metadata: `0x${"00".repeat(32)}`,
    builder: `0x${"00".repeat(32)}`,
  };
  const sig = signPoly1271Order({
    signer,
    order,
    domain: { exchange: "0xE111180000d2663C0091e4f400237545B87B996B", chainId: 137, name: "Polymarket CTF Exchange", version: "2" },
  });
  assert.equal(sig, VECTOR_SIG);
});
